+export function decryptChromiumAes128CbcCookieValue(
+	encryptedValue: Uint8Array,
+	keyCandidates: readonly Buffer[],
+	options: { stripHashPrefix: boolean; treatUnknownPrefixAsPlaintext?: boolean }
