+	encryptedValue: Uint8Array,
+	key: Buffer,
+	options: { stripHashPrefix: boolean }
+): string | null {
+	const buf = Buffer.from(encryptedValue);
+	if (buf.length < 3) return null;
+	const prefix = buf.subarray(0, 3).toString('utf8');
+	if (!/^v\d\d$/.test(prefix)) return null;
