+	const decrypt = (
+		encryptedValue: Uint8Array,
+		opts: { stripHashPrefix: boolean }
+	): string | null => {
+		return decryptChromiumAes256GcmCookieValue(encryptedValue, masterKey.value, {
+			stripHashPrefix: opts.stripHashPrefix,
+		});
+	};
