+		{
+			dbPath,
+		};
+	if (options.profile) dbOptions.profile = options.profile;
+	if (options.includeExpired !== undefined) dbOptions.includeExpired = options.includeExpired;
+	if (options.debug !== undefined) dbOptions.debug = options.debug;
